final:
module top_module (
    input q,
    input l,
    input o,
    output reg invalid_t
);
    always @(*) begin
        case ({q, l, o})
            3'b011: invalid_t = 1'b1;
            3'b110: invalid_t = 1'b0;
            3'b100: invalid_t = 1'b0;
            3'b000: invalid_t = 1'b1;
            3'b001: invalid_t = 1'b1;
            3'b101: invalid_t = 1'b1;
            3'b111: invalid_t = 1'b1;
            3'b010: invalid_t = 1'b0;
        endcase
    end
endmodule
